            ([datetime]$row.LastSeen).ToString($dateFormat).PadRight($dateWidth)
        )
        [void]$sb.AppendLine($line)
    }

    [void]$sb.AppendLine($separator)
    [void]$sb.AppendLine("Total unique error/warning types: $([int]$FrequencyTable.Count)")

