    [int]$errorTotal = [int](($FrequencyTable | Where-Object { [string]$_.Level -in @('ERROR','CRITICAL') } | Measure-Object -Property Count -Sum).Sum)
    [int]$warnTotal  = [int](($FrequencyTable | Where-Object { [string]$_.Level -in @('WARN','WARNING') }   | Measure-Object -Property Count -Sum).Sum)
    [void]$sb.AppendLine("Total occurrences  — ERROR|WARN: $errorTotal | $warnTotal")

    return $sb.ToString()
}

# ---------------------------------------------------------------------------
