            firstSeen  = ([datetime]$row.FirstSeen).ToString('o')   # ISO 8601 round-trip
            lastSeen   = ([datetime]$row.LastSeen).ToString('o')
        })
    }

    # Aggregate summary stats
    [int]$totalErrors   = [int](($FrequencyTable | Where-Object { [string]$_.Level -in @('ERROR','CRITICAL') } | Measure-Object -Property Count -Sum).Sum)
    [int]$totalWarnings = [int](($FrequencyTable | Where-Object { [string]$_.Level -in @('WARN','WARNING') }   | Measure-Object -Property Count -Sum).Sum)

    $output = [PSCustomObject]@{
